# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System;

public class PlayerStats : MonoBehaviour
{
    public static PlayerStats Instance;
    
    public float health = 100f;
    public float maxHealth = 100f;
    public int currency = 1000;
    public int level = 1;
    public float attackPower = 10f;
    public float defense = 5f;
    
    void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }
    
    public void TakeDamage(float damage)
    {
        float finalDamage = CalculateDamage(damage);
        health -= finalDamage;
        
        if (health <= 0)
        {
            health = 0;
            Die();
        }
        
        Debug.Log("Player took " + finalDamage + " damage. Health: " + health);
    }
    
    public float CalculateDamage(float baseDamage)
    {
        float damageReduction = defense / (defense + 100);
        float finalDamage = baseDamage * (1 - damageReduction);
        return Mathf.Max(1f, finalDamage);
    }
    
    public void Heal(float amount)
    {
        health += amount;
        if (health > maxHealth)
        {
            health = maxHealth;
        }
        Debug.Log("Player healed " + amount + ". Health: " + health);
    }
    
    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Added " + amount + " currency. Total: " + currency);
    }
    
    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            Debug.Log("Spent " + amount + " currency. Remaining: " + currency);
            return true;
        }
        Debug.Log("Not enough currency!");
        return false;
    }
    
    public void LevelUp()
    {
        level++;
        maxHealth += 20f;
        health = maxHealth;
        attackPower += 2f;
        defense += 1f;
        Debug.Log("Level up! Now level " + level);
    }
    
    void Die()
    {
        Debug.Log("Player died!");
    }
}

public class CombatSystem : MonoBehaviour
{
    public float CalculatePlayerDamage(float baseAttack, bool isCritical = false)
    {
        float damage = baseAttack + PlayerStats.Instance.attackPower;
        
        if (isCritical)
        {
            damage *= 2f;
        }
        
        return damage;
    }
    
    public void AttackEnemy(Enemy enemy)
    {
        bool isCrit = UnityEngine.Random.value < 0.15f;
        float damage = CalculatePlayerDamage(10f, isCrit);
        enemy.TakeDamage(damage);
        
        if (isCrit)
        {
            Debug.Log("Critical hit!");
        }
    }
}

public class Enemy : MonoBehaviour
{
    public float health = 50f;
    public float attackDamage = 15f;
    public int currencyReward = 50;
    
    public void TakeDamage(float damage)
    {
        health -= damage;
        Debug.Log("Enemy took " + damage + " damage. Health: " + health);
        
        if (health <= 0)
        {
            Die();
        }
    }
    
    public void AttackPlayer()
    {
        PlayerStats.Instance.TakeDamage(attackDamage);
    }
    
    void Die()
    {
        PlayerStats.Instance.AddCurrency(currencyReward);
        Debug.Log("Enemy died!");
        Destroy(gameObject);
    }
}

[Serializable]
public class ShopItem
{
    public string itemName;
    public int price;
    public ItemType type;
    public float value;
}

public enum ItemType
{
    HealthPotion,
    AttackUpgrade,
    DefenseUpgrade,
    MaxHealthUpgrade,
    CurrencyPack
}

public class ShopSystem : MonoBehaviour
{
    public ShopItem[] shopItems;
    
    void Start()
    {
        InitializeShop();
    }
    
    void InitializeShop()
    {
        shopItems = new ShopItem[]
        {
            new ShopItem { itemName = "Small Health Potion", price = 50, type = ItemType.HealthPotion, value = 30f },
            new ShopItem { itemName = "Medium Health Potion", price = 100, type = ItemType.HealthPotion, value = 60f },
            new ShopItem { itemName = "Large Health Potion", price = 200, type = ItemType.HealthPotion, value = 100f },
            new ShopItem { itemName = "Attack Upgrade", price = 500, type = ItemType.AttackUpgrade, value = 5f },
            new ShopItem { itemName = "Defense Upgrade", price = 500, type = ItemType.DefenseUpgrade, value = 3f },
            new ShopItem { itemName = "Max Health Upgrade", price = 750, type = ItemType.MaxHealthUpgrade, value = 50f },
            new ShopItem { itemName = "Small Currency Pack", price = 100, type = ItemType.CurrencyPack, value = 500f },
            new ShopItem { itemName = "Large Currency Pack", price = 500, type = ItemType.CurrencyPack, value = 3000f }
        };
    }
    
    public int CalculateItemPrice(ShopItem item, int playerLevel)
    {
        float priceMultiplier = 1f + (playerLevel * 0.1f);
        return Mathf.RoundToInt(item.price * priceMultiplier);
    }
    
    public bool PurchaseItem(int itemIndex)
    {
        if (itemIndex < 0 || itemIndex >= shopItems.Length)
        {
            Debug.Log("Invalid item index!");
            return false;
        }
        
        ShopItem item = shopItems[itemIndex];
        int finalPrice = CalculateItemPrice(item, PlayerStats.Instance.level);
        
        if (PlayerStats.Instance.SpendCurrency(finalPrice))
        {
            ApplyItemEffect(item);
            Debug.Log("Purchased: " + item.itemName);
            return true;
        }
        
        return false;
    }
    
    void ApplyItemEffect(ShopItem item)
    {
        switch (item.type)
        {
            case ItemType.HealthPotion:
                PlayerStats.Instance.Heal(item.value);
                break;
                
            case ItemType.AttackUpgrade:
                PlayerStats.Instance.attackPower += item.value;
                Debug.Log("Attack power increased to " + PlayerStats.Instance.attackPower);
                break;
                
            case ItemType.DefenseUpgrade:
                PlayerStats.Instance.defense += item.value;
                Debug.Log("Defense increased to " + PlayerStats.Instance.defense);
                break;
                
            case ItemType.MaxHealthUpgrade:
                PlayerStats.Instance.maxHealth += item.value;
                PlayerStats.Instance.health = PlayerStats.Instance.maxHealth;
                Debug.Log("Max health increased to " + PlayerStats.Instance.maxHealth);
                break;
                
            case ItemType.CurrencyPack:
                PlayerStats.Instance.AddCurrency((int)item.value);
                break;
        }
    }
}

public class IAPManager : MonoBehaviour
