    {
        Debug.Log("Processing IAP for " + amount + " currency at $" + realMoneyPrice);
        PlayerStats.Instance.AddCurrency(amount);
    }
    
    public void PurchasePremiumCurrency(int amount)
    {
        PlayerStats.Instance.AddCurrency(amount);
    }
}

public class GameController : MonoBehaviour
{
    public PlayerStats playerStats;
    public ShopSystem shopSystem;
    public CombatSystem combatSystem;
    
    void Start()
    {
        if (playerStats == null)
        {
            playerStats = PlayerStats.Instance;
        }
    }
    
    void Update()
    {
        if (Input.GetKeyDown(KeyCode.Alpha1))
        {
            playerStats.TakeDamage(20f);
        }
        
        if (Input.GetKeyDown(KeyCode.Alpha2))
        {
            playerStats.Heal(30f);
        }
        
        if (Input.GetKeyDown(KeyCode.Alpha3))
        {
            playerStats.AddCurrency(100);
        }
        
        if (Input.GetKeyDown(KeyCode.Alpha4))
        {
            shopSystem.PurchaseItem(0);
        }
    }
}